const value = $json;

const normalize = (v) => String(v || '').replace(/\s+/g, ' ').trim();
const normalizeDate = (input) => {
  const raw = normalize(input).toLowerCase();
  if (!raw) return null;
  const iso = raw.match(/^(\d{4})-(\d{2})-(\d{2})$/);
  if (iso) return `${iso[1]}-${iso[2]}-${iso[3]}`;
  const it = raw.match(/^(\d{1,2})\/(\d{1,2})\/(\d{4})$/);
  if (it) return `${it[3]}-${String(it[2]).padStart(2,'0')}-${String(it[1]).padStart(2,'0')}`;
  return null;
};

const nome = normalize(value.nome).split(' ').filter(Boolean).map(p=>p.charAt(0).toUpperCase()+p.slice(1).toLowerCase()).join(' ');
const telefono = normalize(value.telefono).replace(/[^\d+\s]/g, '');
const email = normalize(value.email).toLowerCase();
const checkin = normalizeDate(value.checkin_input);
const checkout = normalizeDate(value.checkout_input);
const ospitiAdulti = Number(String(value.ospiti_adulti || '').trim());
const ospitiBambini = Number(String(value.ospiti_bambini || '0').trim() || '0');
const roomType = normalize(value.room_type_requested);
const servizi = normalize(value.servizi_richiesti);
const note = normalize(value.note_prenotazione);
const bookingType = normalize(value.booking_type || 'standard_room_booking').toLowerCase();
const lingua = normalize(value.lingua_cliente || 'it').toLowerCase();

let code = '';
let message = '';
if (!nome || !telefono || !email || !checkin || !checkout || Number.isNaN(ospitiAdulti) || ospitiAdulti <= 0) {
  code = 'MISSING_REQUIRED_FIELDS';
  message = 'Dati obbligatori mancanti o non validi.';
}

if (!code) {
  const ci = new Date(`${checkin}T00:00:00Z`);
  const co = new Date(`${checkout}T00:00:00Z`);
  if (!(co > ci)) {
    code = 'INVALID_STAY_RANGE';
    message = 'Check-out deve essere successivo al check-in.';
  }
}

return [{
  json: {
    ...value,
    nome,
    telefono,
    email,
    checkin_date: checkin,
    checkout_date: checkout,
    ospiti_adulti: String(ospitiAdulti || ''),
    ospiti_bambini: String(Number.isNaN(ospitiBambini) ? 0 : ospitiBambini),
    room_type_requested: roomType,
    servizi_richiesti: servizi,
    note_prenotazione: note,
    booking_type: bookingType,
    lingua_cliente: lingua,
    is_valid_payload: !code,
    validation_code: code,
    validation_message: message,
  },
}];

const input = $json;

const providerRaw = String(input.booking_manager_provider || input.pms_provider || '').trim().toLowerCase();
const hasExternalBookingLink = !!String(input.link_booking_esterno || '').trim();

const endpointByProvider = {
  mews: $env.HOTEL_MIDDLEWARE_MEWS_URL || '',
  cloudbeds: $env.HOTEL_MIDDLEWARE_CLOUDBEDS_URL || '',
  siteminder: $env.HOTEL_MIDDLEWARE_SITEMINDER_URL || '',
  cinque_stelle: $env.HOTEL_MIDDLEWARE_5STELLE_URL || '',
};

const provider = endpointByProvider[providerRaw] ? providerRaw : 'manual';
const provider_api_url = endpointByProvider[provider] || $env.HOTEL_MIDDLEWARE_FALLBACK_URL || '';

const integration_mode = provider === 'manual' ? (hasExternalBookingLink ? 'manual_with_external_link' : 'manual_no_link') : 'booking_manager_live';

const bookingPayload = {
  tenant_id: input.tenant_id,
  provider,
  booking_type: input.booking_type || 'standard_room_booking',
  guest: {
    nome: input.nome,
    telefono: input.telefono,
    email: input.email,
    lingua_cliente: input.lingua_cliente || 'it',
  },
  stay: {
    checkin_date: input.checkin_date,
    checkout_date: input.checkout_date,
    ospiti_adulti: Number(input.ospiti_adulti || 0),
    ospiti_bambini: Number(input.ospiti_bambini || 0),
    room_type_requested: input.room_type_requested || null,
    servizi_richiesti: input.servizi_richiesti || null,
    note_prenotazione: input.note_prenotazione || null,
  },
  actions: {
    check_availability: true,
    quote_room_types: true,
    include_services: true,
    create_payment_intent: true,
    create_booking: true,
    trigger_notifications: true,
  },
};

return [{
  json: {
    ...input,
    provider,
    integration_mode,
    provider_api_url,
    supported_providers: ['mews', 'cloudbeds', 'siteminder', 'cinque_stelle'],
    booking_payload: bookingPayload,
  },
}];

const input = $json;
const adapter = input.body || input.data || input;

const success = Boolean(adapter.success);
const paymentRequired = Boolean(adapter.payment_required);
const bookingConfirmed = success && (String(adapter.booking_status || '').toLowerCase() === 'confirmed');
const bookingReference = adapter.booking_reference || '';
const paymentUrl = adapter.payment_url || '';
const totalAmount = adapter.total_amount || null;
const currency = adapter.currency || 'EUR';
const roomType = adapter.room_type || input.room_type_requested || 'camera standard';

let finalReply = '';
if (!success) {
  finalReply = 'Ho raccolto i dati ma non sono riuscito a registrare la prenotazione in questo momento.';
} else if (paymentRequired && paymentUrl) {
  finalReply = `Perfetto, ho trovato disponibilita per ${roomType}. Per completare la prenotazione devi finalizzare il pagamento qui: ${paymentUrl}`;
} else if (bookingConfirmed) {
  finalReply = `Prenotazione confermata con riferimento ${bookingReference || 'in elaborazione'}.`;
} else {
  finalReply = 'Richiesta presa in carico: sto completando la registrazione con la struttura.';
}

return [{
  json: {
    ...input,
    adapter_success: success,
    booking_status: adapter.booking_status || (success ? 'pending' : 'failed'),
    payment_required: paymentRequired,
    payment_url: paymentUrl,
    booking_reference: bookingReference,
    total_amount: totalAmount,
    currency,
    room_type_assigned: roomType,
    adapter_raw: adapter,
    final_reply: finalReply,
  },
}];

