const input = $json;
const success = !!input.adapter_success;

return [{
  json: {
    success,
    code: success ? 'HOTEL_BOOKING_PROCESSED' : 'HOTEL_BOOKING_FAILED',
    message: success ? 'Richiesta prenotazione hotel processata.' : 'Errore durante la registrazione della prenotazione hotel.',
    tenant_id: input.tenant_id,
    booking_type: input.booking_type,
    booking_status: input.booking_status,
    booking_reference: input.booking_reference || null,
    checkin_date: input.checkin_date,
    checkout_date: input.checkout_date,
    room_type_assigned: input.room_type_assigned || null,
    payment_required: !!input.payment_required,
    payment_url: input.payment_url || null,
    total_amount: input.total_amount || null,
    currency: input.currency || 'EUR',
    integration_mode: input.integration_mode,
    provider: input.provider,
    final_reply: input.final_reply || (success ? 'Richiesta soggiorno registrata.' : 'Non sono riuscito a registrare la richiesta soggiorno.'),
  },
}];
